import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"北京交通指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/transportation.md","filePath":"guide/transportation.md","lastUpdated":null}'),r={name:"guide/transportation.md"};function d(n,t,s,h,o,x){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="北京交通指南" tabindex="-1">北京交通指南 <a class="header-anchor" href="#北京交通指南" aria-label="Permalink to &quot;北京交通指南&quot;">​</a></h1><blockquote><p>&quot;地铁纵横，公交便捷，出行无忧。&quot;</p></blockquote><h2 id="地铁" tabindex="-1">地铁 <a class="header-anchor" href="#地铁" aria-label="Permalink to &quot;地铁&quot;">​</a></h2><p>北京地铁是全球最繁忙的地铁系统之一，目前拥有20余条线路，覆盖全市主要景点。</p><h3 id="主要景点地铁站" tabindex="-1">主要景点地铁站 <a class="header-anchor" href="#主要景点地铁站" aria-label="Permalink to &quot;主要景点地铁站&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">地铁线路</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">天安门/故宫</td><td style="text-align:center;">1号线</td><td style="text-align:left;">天安门东/西站</td></tr><tr><td style="text-align:left;">颐和园</td><td style="text-align:center;">4号线</td><td style="text-align:left;">北宫门站</td></tr><tr><td style="text-align:left;">圆明园</td><td style="text-align:center;">4号线</td><td style="text-align:left;">圆明园站</td></tr><tr><td style="text-align:left;">天坛</td><td style="text-align:center;">5号线</td><td style="text-align:left;">天坛东门站</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">6号线</td><td style="text-align:left;">北海北站</td></tr><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">6/8号线</td><td style="text-align:left;">南锣鼓巷站</td></tr><tr><td style="text-align:left;">奥林匹克公园</td><td style="text-align:center;">8号线</td><td style="text-align:left;">奥林匹克公园站</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">1号线</td><td style="text-align:left;">天安门东站</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">8号线</td><td style="text-align:left;">什刹海站</td></tr><tr><td style="text-align:left;">前门</td><td style="text-align:center;">2号线</td><td style="text-align:left;">前门站</td></tr></tbody></table><h3 id="地铁票价" tabindex="-1">地铁票价 <a class="header-anchor" href="#地铁票价" aria-label="Permalink to &quot;地铁票价&quot;">​</a></h3><ul><li>起步价3元（6公里内）</li><li>6-12公里4元</li><li>12-22公里5元</li><li>22-32公里6元</li><li>32公里以上每20公里加1元</li></ul><h3 id="地铁app" tabindex="-1">地铁APP <a class="header-anchor" href="#地铁app" aria-label="Permalink to &quot;地铁APP&quot;">​</a></h3><ul><li><strong>亿通行</strong>：北京地铁官方APP，支持扫码乘车</li><li><strong>北京公交</strong>：可查询地铁线路和到站时间</li></ul><h2 id="公交" tabindex="-1">公交 <a class="header-anchor" href="#公交" aria-label="Permalink to &quot;公交&quot;">​</a></h2><p>北京公交线路众多，基本覆盖所有区域。</p><h3 id="票价" tabindex="-1">票价 <a class="header-anchor" href="#票价" aria-label="Permalink to &quot;票价&quot;">​</a></h3><ul><li>常规线路：2元起</li><li>快速公交：按里程计价</li></ul><h3 id="支付方式" tabindex="-1">支付方式 <a class="header-anchor" href="#支付方式" aria-label="Permalink to &quot;支付方式&quot;">​</a></h3><ul><li>北京公交APP</li><li>亿通行APP</li><li>支付宝/微信乘车码</li><li>市政交通一卡通</li></ul><h2 id="出租车-网约车" tabindex="-1">出租车/网约车 <a class="header-anchor" href="#出租车-网约车" aria-label="Permalink to &quot;出租车/网约车&quot;">​</a></h2><h3 id="出租车" tabindex="-1">出租车 <a class="header-anchor" href="#出租车" aria-label="Permalink to &quot;出租车&quot;">​</a></h3><ul><li><strong>起步价</strong>：14元（3公里内）</li><li><strong>夜间加价</strong>：23:00-5:00加收20%</li><li><strong>等候费</strong>：低速行驶或停车等候每5分钟按1公里计费</li></ul><h3 id="网约车" tabindex="-1">网约车 <a class="header-anchor" href="#网约车" aria-label="Permalink to &quot;网约车&quot;">​</a></h3><ul><li>滴滴出行、美团打车、高德打车等</li><li>高峰期可能加价</li><li>注意定位准确</li></ul><h2 id="共享单车" tabindex="-1">共享单车 <a class="header-anchor" href="#共享单车" aria-label="Permalink to &quot;共享单车&quot;">​</a></h2><p>北京共享单车遍布全城，适合短距离接驳。</p><h3 id="主要品牌" tabindex="-1">主要品牌 <a class="header-anchor" href="#主要品牌" aria-label="Permalink to &quot;主要品牌&quot;">​</a></h3><ul><li>美团单车（黄色）</li><li>哈啰单车（蓝色）</li><li>青桔单车（绿色）</li></ul><h3 id="收费标准" tabindex="-1">收费标准 <a class="header-anchor" href="#收费标准" aria-label="Permalink to &quot;收费标准&quot;">​</a></h3><ul><li>起步价1.5元/30分钟</li><li>超出后1元/15分钟</li></ul><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>注意禁停区域</li><li>不要骑入故宫等景区</li><li>注意交通安全</li></ul><h2 id="机场交通" tabindex="-1">机场交通 <a class="header-anchor" href="#机场交通" aria-label="Permalink to &quot;机场交通&quot;">​</a></h2><h3 id="首都国际机场-pek" tabindex="-1">首都国际机场（PEK） <a class="header-anchor" href="#首都国际机场-pek" aria-label="Permalink to &quot;首都国际机场（PEK）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th><th style="text-align:center;">时间</th><th style="text-align:center;">费用</th></tr></thead><tbody><tr><td style="text-align:left;">机场快轨</td><td style="text-align:left;">东直门/三元桥 → T2/T3</td><td style="text-align:center;">20-30分钟</td><td style="text-align:center;">25元</td></tr><tr><td style="text-align:left;">机场大巴</td><td style="text-align:left;">多条线路</td><td style="text-align:center;">60-90分钟</td><td style="text-align:center;">20-30元</td></tr><tr><td style="text-align:left;">出租车</td><td style="text-align:left;">市中心 → 机场</td><td style="text-align:center;">60-90分钟</td><td style="text-align:center;">100-150元</td></tr><tr><td style="text-align:left;">网约车</td><td style="text-align:left;">市中心 → 机场</td><td style="text-align:center;">60-90分钟</td><td style="text-align:center;">80-120元</td></tr></tbody></table><h3 id="大兴国际机场-pkx" tabindex="-1">大兴国际机场（PKX） <a class="header-anchor" href="#大兴国际机场-pkx" aria-label="Permalink to &quot;大兴国际机场（PKX）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th><th style="text-align:center;">时间</th><th style="text-align:center;">费用</th></tr></thead><tbody><tr><td style="text-align:left;">大兴机场线</td><td style="text-align:left;">草桥 → 机场</td><td style="text-align:center;">20分钟</td><td style="text-align:center;">35元</td></tr><tr><td style="text-align:left;">机场大巴</td><td style="text-align:left;">多条线路</td><td style="text-align:center;">60-120分钟</td><td style="text-align:center;">40元</td></tr><tr><td style="text-align:left;">出租车</td><td style="text-align:left;">市中心 → 机场</td><td style="text-align:center;">60-90分钟</td><td style="text-align:center;">150-200元</td></tr><tr><td style="text-align:left;">网约车</td><td style="text-align:left;">市中心 → 机场</td><td style="text-align:center;">60-90分钟</td><td style="text-align:center;">120-180元</td></tr></tbody></table><h2 id="火车站交通" tabindex="-1">火车站交通 <a class="header-anchor" href="#火车站交通" aria-label="Permalink to &quot;火车站交通&quot;">​</a></h2><h3 id="北京站" tabindex="-1">北京站 <a class="header-anchor" href="#北京站" aria-label="Permalink to &quot;北京站&quot;">​</a></h3><ul><li>地铁2号线北京站</li><li>主要发往东北、华东地区</li></ul><h3 id="北京西站" tabindex="-1">北京西站 <a class="header-anchor" href="#北京西站" aria-label="Permalink to &quot;北京西站&quot;">​</a></h3><ul><li>地铁7号线、9号线北京西站</li><li>主要发往西部、南部地区</li></ul><h3 id="北京南站" tabindex="-1">北京南站 <a class="header-anchor" href="#北京南站" aria-label="Permalink to &quot;北京南站&quot;">​</a></h3><ul><li>地铁4号线、14号线北京南站</li><li>主要高铁线路</li></ul><h3 id="北京北站" tabindex="-1">北京北站 <a class="header-anchor" href="#北京北站" aria-label="Permalink to &quot;北京北站&quot;">​</a></h3><ul><li>地铁2号线、4号线、13号线西直门站</li><li>主要发往内蒙古、延庆</li></ul><h2 id="游览建议" tabindex="-1">游览建议 <a class="header-anchor" href="#游览建议" aria-label="Permalink to &quot;游览建议&quot;">​</a></h2><h3 id="推荐交通方式" tabindex="-1">推荐交通方式 <a class="header-anchor" href="#推荐交通方式" aria-label="Permalink to &quot;推荐交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">情况</th><th style="text-align:left;">推荐方式</th></tr></thead><tbody><tr><td style="text-align:left;">短距离（1-3公里）</td><td style="text-align:left;">共享单车/步行</td></tr><tr><td style="text-align:left;">中距离（3-10公里）</td><td style="text-align:left;">地铁</td></tr><tr><td style="text-align:left;">长距离/地铁不到</td><td style="text-align:left;">公交/打车</td></tr><tr><td style="text-align:left;">机场/火车站</td><td style="text-align:left;">机场快轨/地铁</td></tr><tr><td style="text-align:left;">夜间</td><td style="text-align:left;">出租车/网约车</td></tr></tbody></table><h3 id="交通卡" tabindex="-1">交通卡 <a class="header-anchor" href="#交通卡" aria-label="Permalink to &quot;交通卡&quot;">​</a></h3><p>建议购买「市政交通一卡通」或使用「亿通行」APP，乘坐地铁和公交都有优惠。</p><h3 id="注意事项-1" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项-1" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ol><li><strong>早高峰</strong>：7:30-9:00地铁非常拥挤</li><li><strong>晚高峰</strong>：17:30-19:30交通拥堵</li><li><strong>周一早高峰</strong>：周一上午尤其拥挤</li><li><strong>节假日</strong>：景点周边交通压力大</li><li><strong>安检</strong>：地铁和火车站需安检，提前到达</li></ol><hr><p><strong>💡 提示</strong>：地铁是游览北京最便捷的方式，建议提前下载「亿通行」APP。</p>',52)])])}const u=e(r,[["render",d]]);export{c as __pageData,u as default};
